#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    vector<int> result(n, -1);
    stack<int> st;
    for(int i = n - 1; i >= 0; i--){
        while(!st.empty() && st.top() <= nums[i]) st.pop();
        if(!st.empty()) result[i] = st.top();
        st.push(nums[i]);
    }
    for(int i = 0; i < n; i++) cout << result[i] << ' ';
    return 0;
}
